TYPE
    ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT);
END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd : BOOL;
    SensorPresent : BOOL;
    SensorDefect : BOOL;
    EStop : BOOL;
END_VAR
VAR_OUTPUT
    MotorRun : BOOL;
    RejectSolenoid : BOOL;
END_VAR
VAR
    State : ConveyorState := ST_IDLE;
    RejectTimer : TON;
END_VAR

IF EStop THEN
    State := ST_FAULT;
ELSIF State = ST_FAULT AND NOT EStop THEN
    State := ST_IDLE;
END_IF;

CASE State OF
    ST_IDLE:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        RejectTimer(IN := FALSE, PT := T#500ms);
        IF StartCmd AND NOT EStop THEN
            State := ST_RUNNING;
        END_IF;

    ST_RUNNING:
        MotorRun := TRUE;
        RejectSolenoid := FALSE;
        RejectTimer(IN := FALSE, PT := T#500ms);
        IF SensorPresent AND SensorDefect THEN
            State := ST_REJECTING;
            RejectTimer(IN := TRUE, PT := T#500ms);
        END_IF;

    ST_REJECTING:
        MotorRun := FALSE;
        RejectSolenoid := TRUE;
        RejectTimer(IN := TRUE, PT := T#500ms);
        IF RejectTimer.Q THEN
            State := ST_RUNNING;
        END_IF;

    ST_FAULT:
        MotorRun := FALSE;
        RejectSolenoid := FALSE;
        RejectTimer(IN := FALSE, PT := T#500ms);
END_CASE;

END_PROGRAM

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    ts : REAL;
    err : REAL;
    prevErr : REAL;
    intAcc : REAL;
END_VAR

IF NOT Enable THEN
    Output := 0.0;
    intAcc := 0.0;
    prevErr := 0.0;
ELSE
    ts := TIME_TO_REAL(CycleTime);
    err := Setpoint - ProcessValue;
    intAcc := intAcc + Ki * err * ts;
    Output := Kp * err + intAcc + Kd * (err - prevErr) / ts;
    prevErr := err;
END_IF;

IF Output > 100.0 THEN
    Output := 100.0;
ELSIF Output < 0.0 THEN
    Output := 0.0;
END_IF;

END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow : BOOL;
    LevelHigh : BOOL;
    Pump1Fault : BOOL;
    Pump2Fault : BOOL;
    ManualMode : BOOL;
    ManualP1Run : BOOL;
    ManualP2Run : BOOL;
END_VAR
VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR
VAR
    leadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF leadPump = 1 AND Pump1Fault THEN
        leadPump := 2;
    ELSIF leadPump = 2 AND Pump2Fault THEN
        leadPump := 1;
    END_IF;

    IF LevelLow THEN
        IF leadPump = 1 THEN
            P1Run := TRUE;
            P2Run := FALSE;
        ELSE
            P1Run := FALSE;
            P2Run := TRUE;
        END_IF;
    ELSIF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;

END_PROGRAM

PROGRAM BatchDoseSequence
