                doseTimer(IN := FALSE);
                step := 3;
            END_IF;
        3:
            Valve1 := FALSE;
            Valve2 := FALSE;
            Valve3 := TRUE;
            SeqDone := FALSE;
            SeqActive := TRUE;
            doseTimer(IN := TRUE, PT := T#1s);
            IF doseTimer.Q THEN
                doseTimer(IN := FALSE);
