PROGRAM SafetyInterlock
VAR_INPUT
    EStopOK : BOOL;
    GuardClosed : BOOL;
    ResetPB : BOOL;
END_VAR
VAR_OUTPUT
    MachineEnable : BOOL;
    SafetyFault : BOOL;
END_VAR
VAR
    resetTrigger : R_TRIG;
END_VAR

resetTrigger(CLK := ResetPB);

IF NOT EStopOK OR NOT GuardClosed THEN
    SafetyFault := TRUE;
ELSIF resetTrigger.Q AND EStopOK AND GuardClosed THEN
    SafetyFault := FALSE;
END_IF;

MachineEnable := NOT SafetyFault AND EStopOK AND GuardClosed;

END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
    ProductSensor : BOOL;
    ResetBatch : BOOL;
    BatchTarget : INT := 1000;
END_VAR
VAR_OUTPUT
    BatchCount : INT;
    BatchComplete : BOOL;
    TotalCount : INT;
END_VAR
VAR
    sensorEdge : R_TRIG;
    batchCounter : CTU;
END_VAR

sensorEdge(CLK := ProductSensor);
batchCounter(CU := sensorEdge.Q, R := ResetBatch, PV := BatchTarget);
BatchCount := batchCounter.CV;
BatchComplete := batchCounter.Q;
IF sensorEdge.Q THEN
    TotalCount := TotalCount + 1;
END_IF;

END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    enable : BOOL;
    rawInput : REAL;
    windowSize : INT;
END_VAR
VAR_OUTPUT
    filtered : REAL;
END_VAR
VAR
    buffer : ARRAY[0..9] OF REAL;
    head : INT;
    count : INT;
    sum : REAL;
    effectiveSize : INT;
END_VAR

IF NOT enable THEN
    count := 0;
    head := 0;
    sum := 0.0;
    filtered := 0.0;
ELSE
    IF windowSize < 1 THEN
        effectiveSize := 1;
    ELSIF windowSize > 10 THEN
        effectiveSize := 10;
    ELSE
        effectiveSize := windowSize;
    END_IF;

    IF count < effectiveSize THEN
        sum := sum + rawInput;
        count := count + 1;
    ELSE
        sum := sum - buffer[head] + rawInput;
    END_IF;

    buffer[head] := rawInput;
    head := (head + 1) MOD 10;

    filtered := sum / INT_TO_REAL(count);
END_IF;

END_FUNCTION_BLOCK
